import React, { useState, useEffect, useRef } from 'react';
import { createChatSession } from '../services/geminiService.ts';
import { Language } from '../types.ts';
import { GenerateContentResponse } from '@google/genai';

interface Message {
  role: 'user' | 'model';
  text: string;
  links?: { title: string; uri: string }[];
}

interface Props {
  lang: Language;
}

export const ChatWidget: React.FC<Props> = ({ lang }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: lang === 'es' 
        ? "¡Hola, navegante! Soy Ka'la. ¿En qué puedo ayudarte hoy en las orillas del Cabo?" 
        : "Hello, traveler! I'm Ka'la. How can I help you today on the shores of the Cape?" 
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const chatRef = useRef<any>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    chatRef.current = createChatSession(lang);
  }, [lang]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userText = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userText }]);
    setIsLoading(true);

    try {
      if (!chatRef.current) chatRef.current = createChatSession(lang);

      const responseStream = await chatRef.current.sendMessageStream({ message: userText });

      let fullText = '';
      let links: { title: string; uri: string }[] = [];

      setMessages(prev => [...prev, { role: 'model', text: '' }]);

      for await (const chunk of responseStream) {
        const c = chunk as GenerateContentResponse;
        const partText = c.text || '';
        fullText += partText;

        // Extract grounding links if available
        const chunks = c.candidates?.[0]?.groundingMetadata?.groundingChunks;
        if (chunks) {
          chunks.forEach((ch: any) => {
            if (ch.web?.uri) {
              links.push({ title: ch.web.title || 'Source', uri: ch.web.uri });
            }
          });
        }

        setMessages(prev => {
          const newMessages = [...prev];
          const last = newMessages[newMessages.length - 1];
          last.text = fullText;
          if (links.length > 0) {
            // Dedup links
            last.links = Array.from(new Map(links.map(l => [l.uri, l])).values());
          }
          return newMessages;
        });
      }
    } catch (error) {
      console.error("Chat error:", error);
      setMessages(prev => [...prev, { 
        role: 'model', 
        text: lang === 'es' ? "Parece que la brisa se llevó la señal. Intenta de nuevo." : "It seems the breeze took the signal. Try again." 
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-[300] flex flex-col items-end">
      {/* Chat Window */}
      <div className={`mb-4 w-[90vw] max-w-[380px] h-[500px] bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 flex flex-col overflow-hidden transition-all duration-500 origin-bottom-right ${
        isOpen ? 'scale-100 opacity-100' : 'scale-0 opacity-0 pointer-events-none'
      }`}>
        <div className="bg-[#0b3b52] p-6 flex items-center gap-4">
          <div className="w-10 h-10 rounded-full bg-[#1f7a8c] flex items-center justify-center text-white font-black text-lg border-2 border-white/20">
            K
          </div>
          <div>
            <h3 className="text-white font-black text-sm uppercase tracking-widest leading-none">Ka'la</h3>
            <p className="text-[#CBA76B] text-[10px] font-bold uppercase tracking-tight mt-1">Guía Local AI</p>
          </div>
          <button 
            onClick={() => setIsOpen(false)}
            className="ml-auto p-2 text-white/50 hover:text-white transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4 bg-slate-50/50">
          {messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] p-4 rounded-3xl text-sm leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-[#1f7a8c] text-white rounded-br-none shadow-md' 
                  : 'bg-white text-slate-700 rounded-bl-none shadow-sm border border-slate-100'
              }`}>
                {msg.text}
                {msg.links && msg.links.length > 0 && (
                  <div className="mt-3 pt-3 border-t border-slate-100 space-y-2">
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{lang === 'es' ? 'Fuentes:' : 'Sources:'}</p>
                    {msg.links.map((link, li) => (
                      <a 
                        key={li} 
                        href={link.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="block text-[10px] text-[#1f7a8c] hover:underline truncate font-medium"
                      >
                        • {link.title}
                      </a>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
          {isLoading && (
            <div className="flex justify-start">
              <div className="bg-white p-4 rounded-3xl rounded-bl-none border border-slate-100 shadow-sm flex gap-1">
                <div className="w-1.5 h-1.5 bg-[#1f7a8c]/40 rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-[#1f7a8c]/40 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-1.5 h-1.5 bg-[#1f7a8c]/40 rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
        </div>

        <div className="p-4 bg-white border-t border-slate-50">
          <div className="relative flex items-center">
            <input 
              type="text"
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyPress={e => e.key === 'Enter' && handleSend()}
              placeholder={lang === 'es' ? "Escribe a Ka'la..." : "Ask Ka'la..."}
              className="w-full bg-slate-100 rounded-2xl py-3 pl-4 pr-12 text-sm focus:outline-none focus:ring-2 focus:ring-[#1f7a8c]/20 transition-all font-medium"
            />
            <button 
              onClick={handleSend}
              disabled={isLoading || !input.trim()}
              className="absolute right-2 p-2 bg-[#0b3b52] text-white rounded-xl hover:bg-[#1f7a8c] transition-all disabled:opacity-50 disabled:bg-slate-300"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 12h14M12 5l7 7-7 7" /></svg>
            </button>
          </div>
        </div>
      </div>

      {/* Toggle Button */}
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className={`w-14 h-14 rounded-full flex items-center justify-center text-white shadow-2xl transition-all duration-300 hover:scale-110 active:scale-95 z-50 ${
          isOpen ? 'bg-[#1f7a8c] rotate-90' : 'bg-[#0b3b52]'
        }`}
      >
        {isOpen ? (
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
        ) : (
          <div className="relative">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /></svg>
            <span className="absolute -top-1 -right-1 w-3 h-3 bg-[#CBA76B] rounded-full border-2 border-[#0b3b52]"></span>
          </div>
        )}
      </button>
    </div>
  );
};

