const LocationMap = memo(() => {
  const mapRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (mapRef.current && window.google) {
      const position = { lat: 12.2045, lng: -72.1465 }; // Cabo de la Vela coords roughly
      const map = new google.maps.Map(mapRef.current, {
        center: position,
        zoom: 15,
        mapId: 'DEMO_MAP_ID',
        disableDefaultUI: true,
        styles: [
          { "featureType": "water", "stylers": [{ "color": "#1f7a8c" }] },
          { "featureType": "landscape", "stylers": [{ "color": "#f7f0e3" }] }
        ]
      });

      new google.maps.Marker({
        position: position,
        map: map,
        title: "Apalanchii",
      });
    }
  }, []);

  return (
    <div className="w-full h-96 rounded-[3rem] overflow-hidden shadow-2xl border-4 border-white">
      <div ref={mapRef} className="w-full h-full bg-slate-200" />
    </div>
  );
});

